const data = $input.first().json;
const { randomUUID } = require('crypto');
function parseKeyQuotes(raw) { if (!raw) return []; try { const p = JSON.parse(raw); return Array.isArray(p) ? p : [String(p)]; } catch { return raw.split(',').map(s => s.trim()).filter(Boolean); } }
function escHtml(s) { return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;'); }
const alertId = randomUUID();
const now = new Date();
const timestamp = now.toISOString();
const dateStr = now.toISOString().split('T')[0];
const conversationId = data.conversation_id || '';
const playerId = data.player_id || '';
const agentName = data.agent_name || '';
const severity = data.severity || 'Critical';
const issueCategory = data.issue_category || 'Other';
const summary = data.summary || '';
const alertReason = data.alert_reason || 'Critical issue detected';
const keyQuotes = parseKeyQuotes(data.key_quotes);
const recommendedAction = data.recommended_action || '';
const intercomLink = data.intercom_link || '';
const quotesText = keyQuotes.length > 0 ? keyQuotes.map(q => `_"${q}"_`).join('\n') : '_No direct quotes_';
const slack_blocks = [{ type: 'header', text: { type: 'plain_text', text: ':rotating_light: CRITICAL ALERT - Immediate Action Required', emoji: true } }, { type: 'section', text: { type: 'mrkdwn', text: `*Alert:* ${alertReason}\n*Conversation:* ${conversationId}\n*Player:* ${playerId} | *Agent:* ${agentName}` } }, { type: 'divider' }, { type: 'section', text: { type: 'mrkdwn', text: `*Summary:*\n${summary}` } }, { type: 'section', text: { type: 'mrkdwn', text: `*Player Quotes:*\n${quotesText}` } }, { type: 'section', text: { type: 'mrkdwn', text: `*Recommended Action:*\n${recommendedAction}` } }, { type: 'actions', elements: [{ type: 'button', text: { type: 'plain_text', text: 'View Conversation', emoji: true }, url: intercomLink || 'https://app.intercom.com', style: 'danger' }] }, { type: 'context', elements: [{ type: 'mrkdwn', text: `Alert ID: ${alertId} | ${timestamp}` }] }];
const gmail_subject = `[CRITICAL ALERT] ${issueCategory} - Player ${playerId} - ${dateStr}`;
const gmail_html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px"><div style="background:#dc2626;color:white;padding:20px;border-radius:8px 8px 0 0"><h1 style="margin:0;font-size:22px">CRITICAL ALERT - Immediate Action Required</h1></div><div style="background:#fff5f5;border:2px solid #dc2626;border-top:none;padding:20px;border-radius:0 0 8px 8px"><p><strong>Alert Reason:</strong> <span style="color:#dc2626">${escHtml(alertReason)}</span></p><p><strong>Conversation ID:</strong> ${escHtml(conversationId)}</p><p><strong>Player:</strong> ${escHtml(playerId)} | <strong>Agent:</strong> ${escHtml(agentName)}</p><p><strong>Category:</strong> ${escHtml(issueCategory)} | <strong>Severity:</strong> ${escHtml(severity)}</p><h3>Summary</h3><p>${escHtml(summary)}</p><h3>Key Quotes</h3><ul>${keyQuotes.map(q => `<li><em>${escHtml(q)}</em></li>`).join('')}</ul><h3>Recommended Action</h3><p style="background:#fef9c3;padding:12px;border-radius:4px;font-weight:bold">${escHtml(recommendedAction)}</p><div style="text-align:center;margin-top:24px"><a href="${intercomLink}" style="background:#dc2626;color:white;padding:12px 24px;text-decoration:none;border-radius:4px;font-weight:bold">View in Intercom</a></div><p style="color:#6b7280;font-size:12px;margin-top:20px">Alert ID: ${alertId} | ${timestamp}</p></div></body></html>`;
return [{ json: { alert_id: alertId, date: dateStr, conversation_id: conversationId, player_id: playerId, alert_reason: alertReason, severity, notified_to: 'slack:#critical-alerts, stakeholders-email', responded: false, response_time: '', slack_blocks, slack_text: `:rotating_light: CRITICAL ALERT: ${alertReason} - Player ${playerId}`, gmail_subject, gmail_html, timestamp } }];
